+	defer cancel()
+	out, err := runBDWithEnv(ctx, bdExe, ws, dbPath, map[string]string{
+		"BD_LOCK_TIMEOUT": "200ms",
+	}, "import", "-i", jsonlPath, "--force", "--skip-existing", "--no-git-history")
