+		t.Fatalf("import exceeded timeout (likely hung); output:\n%s", out)
+	}
+	low := strings.ToLower(out)
+	if !strings.Contains(low, "locked") && !strings.Contains(low, "busy") && !strings.Contains(low, "timeout") {
