+	}
+
+	waitResp, err := client.GateWait(&GateWaitArgs{ID: created.ID, Waiters: []string{"deacon/"}})
+	if err != nil {
+		t.Fatalf("GateWait: %v", err)
+	}
+	var waitResult GateWaitResult
